unitsize(0.4 cm);

fill((1,2)--(3,2)--(6,8)--(-2,8)--cycle,gray(0.7));
draw((-4,4 - 2*(-4))--(1,2)--(3,2)--(8,2*8 - 4));
draw((-4,8)--(8,8));

label("$y = |x - 1| + |x - 3|$", (8,2*8 - 4), E);
label("$y = 8$", (8,8), E);

dot("$(1,2)$", (1,2), SW);
dot("$(3,2)$", (3,2), SE);
dot("$(-2,8)$", (-2,8), SW);
dot("$(6,8)$", (6,8), SE);
[/asy]

